    if (!selector || !trackAnchors) {
      setRawAnchorElements([])
      setSelectorError(null)
      return undefined
    }

    return subscribeAnchorSelector(selector, (anchors, error) => {
      setRawAnchorElements(anchors)
      setSelectorError(error)
    })
